mapper.select:
SELECT ka.article_id AS articleId, ka.author_id AS authorId, e.employee_name AS authorName, ka.article_title AS articleTitle, ka.article_category AS articleCategory, ka.article_status AS articleStatus, ka.view_count AS viewCount, ka.created_at AS createdAt FROM knowledge_article ka LEFT JOIN employee e ON ka.author_id = e.employee_id WHERE ka.is_deleted = false
AND ka.article_category = #{category}
AND ka.article_status = #{status}
ORDER BY ka.view_count DESC
ORDER BY ka.created_at DESC
LIMIT #{size} OFFSET #{page} * #{size}
